use crate::types::{
    amount_to_string, parse_amount, EscrowClaim, FactoryError, PaymentStatus, RefundSpawnResponse,
    SessionAuditActor, SpawnSession, SpawnSessionState,
};

pub fn register_escrow_claim(session: &SpawnSession, now_ms: u64) -> EscrowClaim {
    let claim = EscrowClaim {
        session_id: session.session_id.clone(),
        quote_terms_hash: session.quote_terms_hash.clone(),
        payment_address: session.payment.payment_address.clone(),
        chain: session.chain.clone(),
        asset: session.asset.clone(),
        required_gross_amount: session.gross_amount.clone(),
        paid_amount: "0".to_string(),
        payment_status: PaymentStatus::Unpaid,
        refundable: false,
        refunded_at: None,
        created_at: now_ms,
        updated_at: now_ms,
    };

    write_state(|state| {
        state
            .escrow_claims
            .insert(session.session_id.clone(), claim.clone());
    });

    claim
}

pub fn get_escrow_claim(session_id: &str) -> Result<EscrowClaim, FactoryError> {
    read_state(|state| {
        state.escrow_claims.get(session_id).cloned().ok_or_else(|| {
            FactoryError::EscrowClaimNotFound {
                session_id: session_id.to_string(),
            }
        })
    })
}

pub fn record_escrow_payment(
    session_id: &str,
    quote_terms_hash: &str,
    paid_amount: &str,
    now_ms: u64,
) -> Result<EscrowClaim, FactoryError> {
    let paid_amount_value = parse_amount(paid_amount)?;

    write_state(|state| {
        let (expected_quote_terms_hash, required_gross_amount, expires_at, previous_state) =
            {
                let session = state.sessions.get(session_id).ok_or_else(|| {
                    FactoryError::SessionNotFound {
                        session_id: session_id.to_string(),
                    }
                })?;
                (
                    session.quote_terms_hash.clone(),
                    parse_amount(&session.gross_amount)?,
                    session.expires_at,
                    session.state.clone(),
                )
            };

        if expected_quote_terms_hash != quote_terms_hash {
            return Err(FactoryError::QuoteTermsHashMismatch {
                expected: expected_quote_terms_hash,
                received: quote_terms_hash.to_string(),
            });
        }

        if now_ms > expires_at {
            let _ = expire_session_in_state(
                state,
                session_id,
                SessionAuditActor::System,
                now_ms,
                "payment synchronized after expiration",
            )?;
            return Err(FactoryError::SessionExpired {
                session_id: session_id.to_string(),
                expires_at,
            });
        }

        let payment_status = if paid_amount_value >= required_gross_amount {
            PaymentStatus::Paid
        } else if paid_amount_value > 0 {
            PaymentStatus::Partial
        } else {
            PaymentStatus::Unpaid
        };

        {
            let claim = state.escrow_claims.get_mut(session_id).ok_or_else(|| {
                FactoryError::EscrowClaimNotFound {
                    session_id: session_id.to_string(),
                }
            })?;
            claim.paid_amount = amount_to_string(paid_amount_value);
            claim.payment_status = payment_status.clone();
            claim.refundable = false;
            claim.updated_at = now_ms;
        }

        let session =
            state
                .sessions
                .get_mut(session_id)
                .ok_or_else(|| FactoryError::SessionNotFound {
                    session_id: session_id.to_string(),
                })?;
        session.payment_status = payment_status.clone();
        session.refundable = false;
        session.updated_at = now_ms;

        let target_state = if paid_amount_value >= required_gross_amount {
            SpawnSessionState::PaymentDetected
        } else {
            SpawnSessionState::AwaitingPayment
        };

        if session.state != target_state {
            session.state = target_state.clone();
            record_session_audit(
                state,
                session_id,
                Some(previous_state),
                target_state,
                SessionAuditActor::Escrow,
                now_ms,
                "escrow payment synchronized",
            );
        }

        state.escrow_claims.get(session_id).cloned().ok_or_else(|| {
            FactoryError::EscrowClaimNotFound {
                session_id: session_id.to_string(),
            }
        })
    })
}

pub(crate) fn claim_escrow_refund_in_state(
    state: &mut FactoryState,
    session_id: &str,
    now_ms: u64,
) -> Result<RefundSpawnResponse, FactoryError> {
    let session = state
        .sessions
        .get(session_id)
        .cloned()
        .ok_or_else(|| FactoryError::SessionNotFound {
            session_id: session_id.to_string(),
        })?;

    if session.payment_status == PaymentStatus::Refunded {
        let refunded_at = state
            .escrow_claims
            .get(session_id)
            .and_then(|claim| claim.refunded_at)
            .unwrap_or(now_ms);
        return Ok(RefundSpawnResponse {
            session_id: session_id.to_string(),
            state: session.state,
            payment_status: PaymentStatus::Refunded,
            refunded_at,
        });
    }

    if session.state != SpawnSessionState::Expired || !session.refundable {
        return Err(FactoryError::SessionNotRefundable {
            session_id: session_id.to_string(),
            state: session.state,
            payment_status: session.payment_status,
        });
    }

    let claim = state
        .escrow_claims
        .get(session_id)
        .cloned()
        .ok_or_else(|| FactoryError::EscrowClaimNotFound {
            session_id: session_id.to_string(),
        })?;
    if !claim.refundable {
        return Err(FactoryError::SessionNotRefundable {
            session_id: session_id.to_string(),
            state: session.state,
            payment_status: session.payment_status,
        });
    }

    if let Some(canister_id) = session.automaton_canister_id.as_ref() {
        let runtime = state
            .runtimes
            .get_mut(canister_id)
            .ok_or_else(|| FactoryError::AutomatonRuntimeNotFound {
                canister_id: canister_id.clone(),
            })?;
        if runtime.controllers.iter().any(|controller| controller == "factory") {
            complete_controller_handoff(runtime, "factory")?;
        }
    }

    {
        let session = state
            .sessions
            .get_mut(session_id)
            .expect("session existence checked");
        clear_provider_secrets(session, None);
        session.retryable = false;
        session.refundable = false;
        session.payment_status = PaymentStatus::Refunded;
        session.updated_at = now_ms;
    }

    {
        let claim = state
            .escrow_claims
            .get_mut(session_id)
            .expect("claim existence checked");
        claim.payment_status = PaymentStatus::Refunded;
        claim.refundable = false;
        claim.refunded_at = Some(now_ms);
        claim.updated_at = now_ms;
    }

    record_session_audit(
        state,
        session_id,
        Some(SpawnSessionState::Expired),
        SpawnSessionState::Expired,
        SessionAuditActor::Escrow,
        now_ms,
        "refund claimed after expiration",
    );

    Ok(RefundSpawnResponse {
        session_id: session_id.to_string(),
        state: SpawnSessionState::Expired,
        payment_status: PaymentStatus::Refunded,
        refunded_at: now_ms,
    })
}

pub fn claim_escrow_refund(
    session_id: &str,
    now_ms: u64,
) -> Result<RefundSpawnResponse, FactoryError> {
    write_state(|state| claim_escrow_refund_in_state(state, session_id, now_ms))
}

use crate::state::{record_session_audit, write_state, FactoryState};
use crate::types::{
    FactoryError, PaymentStatus, SessionAuditActor, SpawnSession, SpawnSessionState,
};

fn retryable_payment_status(payment_status: &PaymentStatus) -> bool {
    *payment_status == PaymentStatus::Paid
}

pub(crate) fn mark_session_failed_in_state(
    state: &mut FactoryState,
    session_id: &str,
    actor: SessionAuditActor,
    now_ms: u64,
    reason: &str,
) -> Result<SpawnSession, FactoryError> {
    let session = state
        .sessions
        .get(session_id)
        .cloned()
        .ok_or_else(|| FactoryError::SessionNotFound {
            session_id: session_id.to_string(),
        })?;
    let retryable = retryable_payment_status(&session.payment_status) && now_ms <= session.expires_at;

    {
        let session = state
            .sessions
            .get_mut(session_id)
            .expect("session existence checked");
        session.state = SpawnSessionState::Failed;
        session.retryable = retryable;
        session.refundable = false;
        session.updated_at = now_ms;
    }

    if let Some(claim) = state.escrow_claims.get_mut(session_id) {
        claim.refundable = false;
        claim.updated_at = now_ms;
    }

    record_session_audit(
        state,
        session_id,
        Some(session.state),
        SpawnSessionState::Failed,
        actor,
        now_ms,
        reason,
    );

    Ok(state
        .sessions
        .get(session_id)
        .cloned()
        .expect("failed session should remain stored"))
}

pub(crate) fn retry_spawn_session_in_state(
    state: &mut FactoryState,
    session_id: &str,
    actor: SessionAuditActor,
    now_ms: u64,
    reason: &str,
) -> Result<SpawnSession, FactoryError> {
    let session = state
        .sessions
        .get(session_id)
        .cloned()
        .ok_or_else(|| FactoryError::SessionNotFound {
            session_id: session_id.to_string(),
        })?;

    if now_ms > session.expires_at {
        return Err(FactoryError::SessionExpired {
            session_id: session_id.to_string(),
            expires_at: session.expires_at,
        });
    }

    if session.state != SpawnSessionState::Failed || !session.retryable {
        return Err(FactoryError::SessionNotRetryable {
            session_id: session_id.to_string(),
            state: session.state,
        });
    }

    if !retryable_payment_status(&session.payment_status) {
        return Err(FactoryError::SessionNotRetryable {
            session_id: session_id.to_string(),
            state: session.state,
        });
    }

    {
        let session = state
            .sessions
            .get_mut(session_id)
            .expect("session existence checked");
        session.state = SpawnSessionState::PaymentDetected;
        session.retryable = false;
        session.refundable = false;
        session.updated_at = now_ms;
    }

    if let Some(claim) = state.escrow_claims.get_mut(session_id) {
        claim.refundable = false;
        claim.updated_at = now_ms;
    }

    record_session_audit(
        state,
        session_id,
        Some(SpawnSessionState::Failed),
        SpawnSessionState::PaymentDetected,
        actor,
        now_ms,
        reason,
    );

    Ok(state
        .sessions
        .get(session_id)
        .cloned()
        .expect("retried session should remain stored"))
}

pub fn mark_session_failed(
    session_id: &str,
    actor: SessionAuditActor,
    now_ms: u64,
    reason: &str,
) -> Result<SpawnSession, FactoryError> {
    write_state(|state| mark_session_failed_in_state(state, session_id, actor, now_ms, reason))
}

pub fn retry_failed_session(
    session_id: &str,
    actor: SessionAuditActor,
    now_ms: u64,
    reason: &str,
) -> Result<SpawnSession, FactoryError> {
    write_state(|state| retry_spawn_session_in_state(state, session_id, actor, now_ms, reason))
}

use crate::controllers::complete_controller_handoff;
use crate::expiry::expire_spawn_session;
use crate::init::initialize_automaton;
use crate::retry::mark_session_failed_in_state;
use crate::state::{clear_provider_secrets, record_session_audit, read_state, write_state};
use crate::types::{
    amount_to_string, parse_amount, FactoryError, PaymentStatus, SessionAuditActor,
    SpawnExecutionReceipt, SpawnSessionState, SpawnedAutomatonRecord,
};

pub fn execute_spawn(session_id: &str, now_ms: u64) -> Result<SpawnExecutionReceipt, FactoryError> {
    let expires_at = read_state(|state| {
        state
            .sessions
            .get(session_id)
            .map(|session| session.expires_at)
            .ok_or_else(|| FactoryError::SessionNotFound {
                session_id: session_id.to_string(),
            })
    })?;
    if now_ms > expires_at {
        let _ = expire_spawn_session(session_id, now_ms)?;
        return Err(FactoryError::SessionExpired {
            session_id: session_id.to_string(),
            expires_at,
        });
    }

    write_state(|state| {
        let (payment_status, session_state) = {
            let session = state.sessions.get(session_id).ok_or_else(|| {
                FactoryError::SessionNotFound {
                    session_id: session_id.to_string(),
                }
            })?;
            (session.payment_status.clone(), session.state.clone())
        };

        if payment_status != PaymentStatus::Paid {
            return Err(FactoryError::PaymentNotSettled {
                session_id: session_id.to_string(),
                status: payment_status,
            });
        }

        match session_state {
            SpawnSessionState::PaymentDetected | SpawnSessionState::Failed => {}
            SpawnSessionState::Complete => {
                let session = state.sessions.get(session_id).expect("session exists");
                return Ok(SpawnExecutionReceipt {
                    session_id: session.session_id.clone(),
                    automaton_canister_id: session
                        .automaton_canister_id
                        .clone()
                        .expect("completed session has canister id"),
                    automaton_evm_address: session
                        .automaton_evm_address
                        .clone()
                        .expect("completed session has evm address"),
                    funded_amount: session.net_forward_amount.clone(),
                    controller: format!(
                        "controller:{}",
                        session
                            .automaton_canister_id
                            .clone()
                            .expect("completed session has canister id")
                    ),
                    completed_at: session.updated_at,
                });
            }
            state => {
                return Err(FactoryError::SessionNotReadyForSpawn {
                    session_id: session_id.to_string(),
                    state,
                });
            }
        }

        let previous_state = {
            let session = state.sessions.get(session_id).expect("session exists");
            session.state.clone()
        };
        {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            session.state = SpawnSessionState::Spawning;
            session.retryable = false;
            session.refundable = false;
            session.updated_at = now_ms;
        }
        record_session_audit(
            state,
            session_id,
            Some(previous_state),
            SpawnSessionState::Spawning,
            SessionAuditActor::System,
            now_ms,
            "spawn execution started",
        );

        state.next_automaton_nonce += 1;

        let version_commit = state.version_commit.clone();
        let mut runtime = {
            let session = state.sessions.get(session_id).expect("session exists");
            let canister_id = session
                .automaton_canister_id
                .clone()
                .unwrap_or_else(|| format!("automaton-{:04}", state.next_automaton_nonce));
            let evm_address = session
                .automaton_evm_address
                .clone()
                .unwrap_or_else(|| format!("0x{:040x}", state.next_automaton_nonce));
            initialize_automaton(session, canister_id, evm_address, now_ms)
        };

        {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            session.automaton_canister_id = Some(runtime.canister_id.clone());
            session.automaton_evm_address = Some(runtime.evm_address.clone());
            session.state = SpawnSessionState::FundingAutomaton;
            session.updated_at = now_ms;
        }
        record_session_audit(
            state,
            session_id,
            Some(SpawnSessionState::Spawning),
            SpawnSessionState::FundingAutomaton,
            SessionAuditActor::System,
            now_ms,
            "automaton initialized",
        );

        let net_forward_amount = match {
            let session = state.sessions.get(session_id).expect("session exists");
            parse_amount(&session.net_forward_amount)?
        } {
            Ok(value) => value,
            Err(error) => {
                let _ = mark_session_failed_in_state(
                    state,
                    session_id,
                    SessionAuditActor::System,
                    now_ms,
                    "spawn funding preparation failed",
                )?;
                return Err(error);
            }
        };
        runtime.funded_amount = amount_to_string(net_forward_amount);
        runtime.last_funded_at = Some(now_ms);

        let controller = match complete_controller_handoff(&mut runtime, "factory") {
            Ok(controller) => controller,
            Err(error) => {
                state.runtimes.insert(runtime.canister_id.clone(), runtime);
                let _ = mark_session_failed_in_state(
                    state,
                    session_id,
                    SessionAuditActor::System,
                    now_ms,
                    "controller handoff failed",
                )?;
                return Err(error);
            }
        };

        let registry_record = {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            clear_provider_secrets(session, Some(&mut runtime));
            session.state = SpawnSessionState::Complete;
            session.retryable = false;
            session.refundable = false;
            session.updated_at = now_ms;

            SpawnedAutomatonRecord {
                canister_id: runtime.canister_id.clone(),
                steward_address: session.steward_address.clone(),
                evm_address: runtime.evm_address.clone(),
                chain: session.chain.clone(),
                session_id: session.session_id.clone(),
                parent_id: session.parent_id.clone(),
                child_ids: session.child_ids.clone(),
                created_at: now_ms,
                version_commit,
            }
        };

        if let Some(parent_id) = registry_record.parent_id.as_ref() {
            if let Some(parent) = state.registry.get_mut(parent_id) {
                if parent
                    .child_ids
                    .iter()
                    .all(|child_id| child_id != &registry_record.canister_id)
                {
                    parent.child_ids.push(registry_record.canister_id.clone());
                }
            }
        }

        state
            .runtimes
            .insert(runtime.canister_id.clone(), runtime.clone());
        state
            .registry
            .insert(registry_record.canister_id.clone(), registry_record);
        record_session_audit(
            state,
            session_id,
            Some(SpawnSessionState::FundingAutomaton),
            SpawnSessionState::Complete,
            SessionAuditActor::System,
            now_ms,
            "spawn completed and controller handoff finalized",
        );

        Ok(SpawnExecutionReceipt {
            session_id: session_id.to_string(),
            automaton_canister_id: runtime.canister_id,
            automaton_evm_address: runtime.evm_address,
            funded_amount: amount_to_string(net_forward_amount),
            controller,
            completed_at: now_ms,
        })
    })
}

use crate::escrow::{claim_escrow_refund, register_escrow_claim};
use crate::expiry::expire_spawn_session;
use crate::retry::retry_failed_session;
use crate::state::{read_state, record_session_audit, write_state};
use crate::types::{
    amount_to_string, hash_quote_terms, parse_amount, CreateSpawnSessionRequest,
    CreateSpawnSessionResponse, FactoryError, RefundSpawnResponse, SessionAuditActor,
    SpawnPaymentInstructions, SpawnQuote, SpawnSession, SpawnSessionState,
    SpawnSessionStatusResponse, SpawnedAutomatonRegistryPage,
};

fn ensure_steward(caller: &str, session_id: &str) -> Result<(), FactoryError> {
    read_state(|state| {
        let session = state.sessions.get(session_id).ok_or_else(|| FactoryError::SessionNotFound {
            session_id: session_id.to_string(),
        })?;

        if session.steward_address == caller {
            return Ok(());
        }

        Err(FactoryError::UnauthorizedSteward {
            caller: caller.to_string(),
            session_id: session_id.to_string(),
        })
    })
}

pub fn create_spawn_session(
    request: CreateSpawnSessionRequest,
    now_ms: u64,
) -> Result<CreateSpawnSessionResponse, FactoryError> {
    let (session, quote) = write_state(|state| {
        if state.paused {
            return Err(FactoryError::FactoryPaused { pause: true });
        }

        let gross_amount_value = parse_amount(&request.gross_amount)?;
        let platform_fee_value = parse_amount(state.fee_config.amount_for(&request.asset))?;
        let creation_cost_value =
            parse_amount(state.creation_cost_quote.amount_for(&request.asset))?;
        let required_minimum = platform_fee_value + creation_cost_value;

        if gross_amount_value < required_minimum {
            return Err(FactoryError::GrossBelowRequiredMinimum {
                provided: request.gross_amount.clone(),
                required: amount_to_string(required_minimum),
            });
        }

        state.next_session_nonce += 1;
        let session_id = format!("session-{}-{}", now_ms, state.next_session_nonce);
        let expires_at = now_ms + state.session_ttl_ms;
        let platform_fee = amount_to_string(platform_fee_value);
        let creation_cost = amount_to_string(creation_cost_value);
        let net_forward_amount = amount_to_string(gross_amount_value - required_minimum);
        let quote_terms_hash = hash_quote_terms(&[
            &session_id,
            &request.steward_address,
            request.asset.as_str(),
            &request.gross_amount,
            &platform_fee,
            &creation_cost,
            &net_forward_amount,
            &expires_at.to_string(),
            &state.payment_address,
        ]);
        let payment = SpawnPaymentInstructions {
            session_id: session_id.clone(),
            chain: request.config.chain.clone(),
            asset: request.asset.clone(),
            payment_address: state.payment_address.clone(),
            gross_amount: request.gross_amount.clone(),
            quote_terms_hash: quote_terms_hash.clone(),
            expires_at,
        };
        let session = SpawnSession {
            session_id: session_id.clone(),
            steward_address: request.steward_address.clone(),
            chain: request.config.chain.clone(),
            asset: request.asset.clone(),
            gross_amount: request.gross_amount.clone(),
            platform_fee: platform_fee.clone(),
            creation_cost: creation_cost.clone(),
            net_forward_amount: net_forward_amount.clone(),
            quote_terms_hash: quote_terms_hash.clone(),
            expires_at,
            state: SpawnSessionState::AwaitingPayment,
            retryable: false,
            refundable: false,
            payment_status: crate::types::PaymentStatus::Unpaid,
            automaton_canister_id: None,
            automaton_evm_address: None,
            parent_id: request.parent_id.clone(),
            child_ids: Vec::new(),
            config: request.config.clone(),
            created_at: now_ms,
            updated_at: now_ms,
            payment: payment.clone(),
        };
        let quote = SpawnQuote {
            session_id: session_id.clone(),
            chain: request.config.chain.clone(),
            asset: request.asset.clone(),
            gross_amount: request.gross_amount.clone(),
            platform_fee,
            creation_cost,
            net_forward_amount,
            quote_terms_hash,
            expires_at,
            payment,
        };

        state.sessions.insert(session_id.clone(), session.clone());
        record_session_audit(
            state,
            &session_id,
            None,
            SpawnSessionState::AwaitingPayment,
            SessionAuditActor::User,
            now_ms,
            "session created",
        );

        Ok((session, quote))
    })?;

    register_escrow_claim(&session, now_ms);

    Ok(CreateSpawnSessionResponse { session, quote })
}

pub fn get_spawn_session(session_id: &str) -> Result<SpawnSessionStatusResponse, FactoryError> {
    read_state(|state| {
        let session = state.sessions.get(session_id).cloned().ok_or_else(|| {
            FactoryError::SessionNotFound {
                session_id: session_id.to_string(),
            }
        })?;
        let audit = state.audit_log.get(session_id).cloned().unwrap_or_default();

        Ok(SpawnSessionStatusResponse { session, audit })
    })
}

pub fn retry_spawn_session(
    caller: &str,
    session_id: &str,
    now_ms: u64,
) -> Result<SpawnSessionStatusResponse, FactoryError> {
    ensure_steward(caller, session_id)?;
    let _ = expire_spawn_session(session_id, now_ms)?;
    retry_failed_session(
        session_id,
        SessionAuditActor::User,
        now_ms,
        "retry requested by steward",
    )?;
    get_spawn_session(session_id)
}

pub fn claim_spawn_refund(
    caller: &str,
    session_id: &str,
    now_ms: u64,
) -> Result<RefundSpawnResponse, FactoryError> {
    ensure_steward(caller, session_id)?;
    let _ = expire_spawn_session(session_id, now_ms)?;
    claim_escrow_refund(session_id, now_ms)
}

pub fn list_spawned_automatons(
    cursor: Option<&str>,
    limit: usize,
) -> Result<SpawnedAutomatonRegistryPage, FactoryError> {
    if limit == 0 {
        return Err(FactoryError::InvalidPaginationLimit { limit });
    }

    read_state(|state| {
        let mut items: Vec<crate::types::SpawnedAutomatonRecord> = Vec::new();
        let mut next_cursor = None;
        let mut seen_cursor = cursor.is_none();

        for (canister_id, record) in &state.registry {
            if !seen_cursor {
                if Some(canister_id.as_str()) == cursor {
                    seen_cursor = true;
                }
                continue;
            }

            if items.len() == limit {
                next_cursor = Some(
                    items
                        .last()
                        .expect("page has at least one item")
                        .canister_id
                        .clone(),
                );
                break;
            }

            items.push(record.clone());
        }

        Ok(SpawnedAutomatonRegistryPage { items, next_cursor })
    })
}

pub fn get_spawned_automaton(
    canister_id: &str,
) -> Result<crate::types::SpawnedAutomatonRecord, FactoryError> {
    read_state(|state| {
        state.registry.get(canister_id).cloned().ok_or_else(|| {
            FactoryError::RegistryRecordNotFound {
                canister_id: canister_id.to_string(),
            }
        })
    })
}

